<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('patient'); require_once __DIR__.'/../../backend/shared/layout.php'; $pid=$_SESSION['user']['id'];$v=db()->prepare('SELECT * FROM visits WHERE patient_id=? ORDER BY visit_date DESC,id DESC');$v->execute([$pid]);$visits=$v->fetchAll(); app_header('Timeline ทั้งหมด','patient','portal');?><a class="back" href="portal.php">← กลับหน้าข้อมูลของฉัน</a><div class="card"><h3>Timeline ทั้งหมด</h3><div class="timeline"><?php foreach($visits as $vv):?><div class="tl-item"><div class="tl-head"><div><div class="tl-title"><?=e($vv['visit_date'])?> · <?=e($vv['hospital_name'])?></div><div class="tl-meta"><?=e($vv['department'])?> · <?=e($vv['ward'])?> · แพทย์ <?=e($vv['doctor_name'])?></div></div><a class="btn secondary" href="visit-detail.php?id=<?=$vv['id']?>">ดูรายละเอียด</a></div><p><?=e($vv['chief_complaint'])?></p></div><?php endforeach;?></div></div><?php app_footer();?>
